class TestGetLimits:
    def test_limits_disabled_returns_404(self, client, db) -> None:
        """When fetch_limits=false, endpoint returns 404."""
        with patch("agentpulse.api.sessions.get_settings") as mock_settings:
            mock_settings.return_value.fetch_limits = False
            resp = client.get("/api/v1/limits")
            assert resp.status_code == 404
            assert "not enabled" in resp.json()["detail"]

    def test_limits_unavailable_returns_404(self, client, db) -> None:
        """When fetch_limits=true but get_limits returns None, returns 404."""
        with (
            patch("agentpulse.api.sessions.get_settings") as mock_settings,
            patch(
                "agentpulse.api.sessions.get_limits", new_callable=AsyncMock
            ) as mock_get_limits,
        ):
            mock_settings.return_value.fetch_limits = True
            mock_get_limits.return_value = None
            resp = client.get("/api/v1/limits")
            assert resp.status_code == 404
            assert "unavailable" in resp.json()["detail"]

    def test_limits_returns_data(self, client, db) -> None:
        """When fetch_limits=true and get_limits returns data, returns 200."""
        sample_limits = {
            "available": True,
            "fetched_at": 1000.0,
            "age_seconds": 10.0,
            "stale": False,
            "refresh_after": 1120.0,
            "five_hour": {
                "utilization": 0.25,
                "resets_at": 2000,
            },
        }
        with (
            patch("agentpulse.api.sessions.get_settings") as mock_settings,
            patch(
                "agentpulse.api.sessions.get_limits", new_callable=AsyncMock
            ) as mock_get_limits,
        ):
            mock_settings.return_value.fetch_limits = True
            mock_get_limits.return_value = sample_limits
            resp = client.get("/api/v1/limits")
            assert resp.status_code == 200
            data = resp.json()
            assert data["available"] is True
            assert data["fetched_at"] == 1000.0
            assert "five_hour" in data


class TestGetLimitsHistory:
    def test_limits_history_disabled_returns_404(self, client, db) -> None:
        """When fetch_limits=false, history endpoint returns 404."""
        with patch("agentpulse.api.sessions.get_settings") as mock_settings:
            mock_settings.return_value.fetch_limits = False
            resp = client.get("/api/v1/limits/history")
            assert resp.status_code == 404
            assert "not enabled" in resp.json()["detail"]

    def test_limits_history_returns_data(self, client, db) -> None:
        """Returns formatted history from claude_limits table."""
        # Seed two rows
        run_async(
            schema.insert_limits(
                db,
                fetched_at=1000.0,
                raw_response=json.dumps({"five_hour": {"utilization": 0.1}}),
            )
        )
        run_async(
            schema.insert_limits(
                db,
                fetched_at=2000.0,
                raw_response=json.dumps({"five_hour": {"utilization": 0.2}}),
            )
        )

        with patch("agentpulse.api.sessions.get_settings") as mock_settings:
            mock_settings.return_value.fetch_limits = True
            resp = client.get("/api/v1/limits/history")
            assert resp.status_code == 200
            data = resp.json()
            assert len(data) == 2
            # Ordered newest first
            assert data[0]["fetched_at"] == 2000.0
            assert data[1]["fetched_at"] == 1000.0
            # Check structure
            assert "id" in data[0]
            assert "age_seconds" in data[0]
            assert "data" in data[0]
            assert data[0]["data"]["five_hour"]["utilization"] == 0.2

    def test_limits_history_pagination(self, client, db) -> None:
        """Verify limit and offset query params work."""
        # Seed 5 rows
        for i in range(5):
            run_async(
                schema.insert_limits(
                    db,
                    fetched_at=float(1000 + i * 100),
                    raw_response=json.dumps({"index": i}),
                )
            )

        with patch("agentpulse.api.sessions.get_settings") as mock_settings:
            mock_settings.return_value.fetch_limits = True

            # Limit to 2
            resp = client.get("/api/v1/limits/history?limit=2")
            assert resp.status_code == 200
            data = resp.json()
            assert len(data) == 2
            # Newest first
            assert data[0]["fetched_at"] == 1400.0
            assert data[1]["fetched_at"] == 1300.0

            # Offset 2, limit 2
            resp = client.get("/api/v1/limits/history?limit=2&offset=2")
            data = resp.json()
            assert len(data) == 2
            assert data[0]["fetched_at"] == 1200.0
            assert data[1]["fetched_at"] == 1100.0

    def test_limits_history_since_filter(self, client, db) -> None:
        """Verify since query param filters by fetched_at."""
        run_async(
            schema.insert_limits(
                db,
                fetched_at=1000.0,
                raw_response=json.dumps({}),
            )
        )
        run_async(
            schema.insert_limits(
                db,
                fetched_at=2000.0,
                raw_response=json.dumps({}),
            )
        )

        with patch("agentpulse.api.sessions.get_settings") as mock_settings:
            mock_settings.return_value.fetch_limits = True
            resp = client.get("/api/v1/limits/history?since=1500.0")
            assert resp.status_code == 200
            data = resp.json()
            assert len(data) == 1
            assert data[0]["fetched_at"] == 2000.0
